query GetPushMessages($unreadOnly: Boolean, $withHidden: Boolean, $cultureName: String, $after: String, $first: Int) {
  pushMessages(
    unreadOnly: $unreadOnly
    withHidden: $withHidden
    cultureName: $cultureName
    after: $after
    first: $first
  ) {
    totalCount
    items {
      ...pushMessage
      __typename
    }
    __typename
  }
  unreadCount: pushMessages(unreadOnly: true, cultureName: $cultureName) {
    totalCount
    __typename
  }
  unreadCountWithHidden: pushMessages(
    unreadOnly: true
    withHidden: true
    cultureName: $cultureName
  ) {
    totalCount
    __typename
  }
}

fragment pushMessage on PushMessageType {
  id
  createdDate
  shortMessage
  isRead
  isHidden
  __typename
}
